from decimal import Decimal, ROUND_HALF_UP


class PaymentProcessingError(Exception):
    pass


def process_payment(user, cart_items, payment_details):
    role = getattr(user, "role", None)
    if role is None and isinstance(user, dict):
        role = user.get("role")

    if role not in {"basic", "premium", "enterprise"}:
        raise ValueError("Invalid user role")

    discount_map = {
        "basic": Decimal("0.00"),
        "premium": Decimal("0.15"),
        "enterprise": Decimal("0.30"),
    }
    discount_rate = discount_map[role]

    if not isinstance(cart_items, list) or not cart_items:
        raise ValueError("cart_items must be a non-empty list")

    subtotal = Decimal("0.00")
    for item in cart_items:
        if isinstance(item, dict):
            price = item.get("price")
            quantity = item.get("quantity", 1)
        else:
            price = getattr(item, "price", None)
            quantity = getattr(item, "quantity", 1)

        if price is None:
            raise ValueError("Each cart item must include a price")
        if quantity is None or quantity <= 0:
            raise ValueError("Each cart item must have a positive quantity")

        line_total = Decimal(str(price)) * Decimal(str(quantity))
        subtotal += line_total

    discount_amount = (subtotal * discount_rate).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    total = (subtotal - discount_amount).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

    if not payment_details or not isinstance(payment_details, dict):
        raise ValueError("payment_details must be a non-empty dictionary")

    required_fields = {"card_number", "expiry_month", "expiry_year", "cvv"}
    missing = required_fields - payment_details.keys()
    if missing:
        raise ValueError(f"Missing payment details: {', '.join(sorted(missing))}")

    payment_result = _charge_payment(total, payment_details)

    return {
        "role": role,
        "subtotal": float(subtotal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)),
        "discount_percentage": int(discount_rate * 100),
        "discount_amount": float(discount_amount),
        "total_charged": float(total),
        "payment_status": "success" if payment_result["success"] else "failed",
        "transaction_id": payment_result.get("transaction_id"),
    }


def _charge_payment(amount, payment_details):
    card_number = str(payment_details.get("card_number", "")).replace(" ", "")
    cvv = str(payment_details.get("cvv", ""))
    expiry_month = payment_details.get("expiry_month")
    expiry_year = payment_details.get("expiry_year")

    if not card_number.isdigit() or len(card_number) < 12:
        raise PaymentProcessingError("Invalid card number")
    if not cvv.isdigit() or len(cvv) not in {3, 4}:
        raise PaymentProcessingError("Invalid CVV")
    if not isinstance(expiry_month, int) or not 1 <= expiry_month <= 12:
        raise PaymentProcessingError("Invalid expiry month")
    if not isinstance(expiry_year, int) or expiry_year < 2024:
        raise PaymentProcessingError("Invalid expiry year")
    if amount <= 0:
        raise PaymentProcessingError("Charge amount must be greater than zero")

    return {
        "success": True,
        "transaction_id": f"txn_{card_number[-4:]}_{int(amount * 100)}",
    }